{
  "experiment_plan": {
    "what_to_compare": "淮河境界の直近にある北側都市と南側都市を比較する地理的RDD。主要比較は、境界からの緯度距離がほぼ同じで政策のみが異なる都市間の冬季TSP、平均寿命、心肺疾患死亡率、ならびに代替経路指標（室内暖房改善、燃料利用、冬季行動、医療アクセス）である。",
    "what_to_measure": "1) 冬季TSP濃度、2) 平均寿命または年齢別死亡率から構成した寿命指標、3) 心肺疾患死亡率、4) がん・外因死など他死因死亡率、5) 室内暖房関連指標、燃料構成、冬季活動パターン、医療アクセス指標、6) 年齢層別・居住期間別の死亡率/寿命指標。",
    "procedure": "1) 淮河からの緯度距離をrunning variableとして、境界近傍の都市サンプルを抽出する。2) 帯域幅を複数設定し、局所線形RDDを主分析とする。3) 3次多項式RDDも補助的に推定し、次数感度を確認する。4) まず政策境界でのTSP不連続を第一段階として推定する。5) 次に平均寿命、心肺疾患死亡率、他死因死亡率の不連続を推定する。6) 代替経路を検証するため、室内暖房改善、燃料利用、冬季行動、医療アクセスの不連続を別途推定する。7) 年齢層別・曝露期間別に異質性分析を行う。8) 年別・季節別のサブサンプルで短期効果と長期累積効果を分離する。9) プレースボー境界や偽のカットオフで同様の分析を行い、設計の妥当性を確認する。",
    "identification_assumptions": [
      {
        "id": "IA1",
        "description": "淮河境界の近傍では、政策以外の潜在的交絡要因が緯度距離に対して滑らかに変化し、境界で不連続に変化しない。",
        "if_violated": "境界での寿命差や死亡率差が政策以外の地理・経済・医療要因によって説明され、RDD推定が因果効果を識別できない。"
      },
      {
        "id": "IA2",
        "description": "淮河をまたぐ政策割当は、都市の潜在的健康トレンドや人口選択によって操作されていない。",
        "if_violated": "境界近傍の都市が政策を見越して人口構成や産業構造を選択的に変えており、処置割当が準ランダムでなくなる。"
      },
      {
        "id": "IA3",
        "description": "政策境界はTSP曝露に実質的な第一段階を生み、かつその曝露差は測定誤差で完全には希釈されない。",
        "if_violated": "北側と南側でTSP差が十分に観測されず、政策が曝露を通じて健康に影響したかを識別できない。"
      },
      {
        "id": "IA4",
        "description": "平均寿命、心肺疾患死亡率、他死因死亡率、代替経路指標の測定誤差は境界の両側で系統的に異ならない。",
        "if_violated": "観測上の不連続が実際の健康差ではなく、データ品質や記録方法の差によって生じる。"
      },
      {
        "id": "IA5",
        "description": "境界近傍での人口移動や死亡登録の選別が、政策境界に応じて不連続に起きていない。",
        "if_violated": "健康状態の悪い個体の移住や死亡登録の欠落が境界で偏り、死亡率や寿命推定が歪む。"
      }
    ],
    "hypothesis_rules": [
      {
        "id": "H1",
        "accept_if": "境界で北側のTSPが南側より有意に高く、同じ帯域幅・複数仕様で平均寿命が北側で一貫して低く、かつ心肺疾患死亡率も同方向に上昇する。",
        "reject_if": "TSPの不連続が確認されるにもかかわらず、平均寿命の不連続が帯域幅や仕様を変えても一貫せず、方向も安定しない。",
        "hold_if": "TSPの不連続はあるが、平均寿命の推定が統計的に不確実で、仕様依存性が高く結論が安定しない。"
      },
      {
        "id": "H2",
        "accept_if": "TSPの不連続を統制しても平均寿命の不連続が残り、同時に室内暖房改善、燃料利用、冬季行動、医療アクセスのいずれかに境界で有意な不連続が観察される。",
        "reject_if": "TSPを媒介として調整すると寿命不連続が消え、代替経路指標にも境界で系統的な不連続が見られない。",
        "hold_if": "寿命不連続は残るが、代替経路指標の不連続が弱いか不安定で、非TSP経路の寄与を特定できない。"
      },
      {
        "id": "H3",
        "accept_if": "平均寿命の低下と同時に心肺疾患死亡率の不連続が明確に現れ、他死因死亡率の不連続は小さいか不明確である。",
        "reject_if": "平均寿命の不連続があるのに心肺疾患死亡率の不連続がなく、他死因死亡率の変化が主要な説明になっている。",
        "hold_if": "心肺疾患死亡率は上昇するが、他死因との比較で媒介経路の優位性が統計的に十分に示せない。"
      },
      {
        "id": "H4",
        "accept_if": "高齢層、長期居住層、または政策導入後の曝露期間が長い層で効果がより大きく、短期冬季死亡増加に加えて慢性疾患関連死亡の遅行的増加が確認される。",
        "reject_if": "年齢層別・曝露期間別に効果差がなく、短期死亡増加のみで説明でき、累積曝露の寄与が見られない。",
        "hold_if": "一部の年齢層で効果差が示唆されるが、居住期間や遅行効果との整合性が弱く、累積曝露仮説を確証できない。"
      }
    ],
    "analysis_forks": [
      "主分析を局所線形RDDにするか、3次多項式RDDを主分析にするか",
      "帯域幅を狭くして内部妥当性を優先するか、広くして精度を優先するか",
      "アウトカムを平均寿命ベースで見るか、年齢別死亡率ベースで見るか",
      "媒介分析でTSPを明示的に第一段階として扱うか、政策ダミーの reduced form を中心にするか",
      "代替経路指標を個別に検証するか、合成指標としてまとめるか",
      "心肺疾患死亡率を主要媒介として扱うか、他死因との比較を補助分析に留めるか",
      "年齢層別異質性を事前指定の主要分析にするか、探索的分析にするか",
      "プレースボー境界検証を主要な妥当性確認にするか、補助的診断にするか"
    ]
  }
}
